-- Порции текста для урока "Что такое SRE и зачем" (модуль foundations)
INSERT INTO lesson_content_chunks (lesson_id, chunk_index, body_text)
SELECT l.id, v.chunk_index, v.body_text
FROM lessons l
JOIN modules m ON m.id = l.module_id AND m.slug = 'foundations'
JOIN (VALUES
  (1, 'SRE — это «просто»: 1) Определиться с нужным SLA. 2) Начать мониторить соблюдение SLA и бюджет ошибок. 3) Подумать, почему SLA не соблюдается. 4) Улучшить сервис. 5) Повторять шаги 3 и 4 в цикле.

Печально, но: 50% команд не может справиться с первым пунктом. 90% не справляются со вторым. 99% — с третьим. Ирония кавычек вокруг слова «просто» — ключ к пониманию всей дисциплины. Концептуально SRE действительно проста: определи, что значит «работает», измерь, как часто оно не работает, и чини. Но между теорией и практикой лежит пропасть.'),
  (2, 'Почему 50% не могут определить SLA? Потому что для этого нужно ответить на вопросы, которые никто не хочет задавать. Кому принадлежит сервис? Кто его пользователь? Что значит «работает» — возвращает 200 OK или действительно решает задачу клиента? Определение SLA — это не техническое упражнение. Это политическое решение, требующее согласия между разработкой, бизнесом и эксплуатацией.

«В идеальном мире все любят говорить про красивые циферки SLA, а на деле непонятно кто за сервис отвечает и кому этот SLA нужен.» — практик из крупного банка.'),
  (3, 'Почему 90% не могут мониторить? Потому что мониторинг — это не «поставить Grafana». Это выбрать правильные метрики, настроить правильные пороги, обеспечить правильную маршрутизацию алертов и добиться того, чтобы люди на них реагировали. Мониторинг без реакции — это не мониторинг.

Когда алертов слишком много, инженеры начинают их игнорировать (alert fatigue). Хороший индикатор качества алертинга — соотношение 80/20: на каждые 10 алертов 8 должны говорить о реальной проблеме.'),
  (4, 'Почему 99% не могут анализировать? Потому что анализ требует культуры: blameless-постмортемы, систематическая классификация причин и воля к исполнению action items. Культура анализа — это готовность организации смотреть правде в глаза: мы сломали прод не потому, что кто-то виноват, а потому что система позволяет это сломать.

Главная проблема внедрения SRE — не техническая, а организационная. Доступность = деньги. Это единственный аргумент, который работает. SRE — это система обратной связи. Без обратной связи любая система деградирует.')
AS v(chunk_index, body_text) ON true
WHERE l.title = 'Что такое SRE и зачем'
ON CONFLICT (lesson_id, chunk_index) DO NOTHING;
